func (r *AccountRepo) GetAccountByID(ctx context.Context, id int64) (domain.Account, error) {
    sel := dblib.Psql.Select("*").From("accounts").Where(sq.Eq{"id": id})
    acc, err := dblib.SelectRow(ctx, r.db, sel, pgx.RowToStructByName[domain.Account])
    if err != nil {
        return domain.Account{}, err
    }
    return acc, nil
}
